CREATE OR REPLACE VIEW vw_series WITH (security_invoker = ON) AS
SELECT
  t.serie_id,
  calc_series_name(t.serie_id) AS name,
  t.series_number,
  t.show_code,
  t.title,
  t.description,
  t.network,
  t.premiere_date,
  t.finale_date,
  calc_series_total_seasons(t.serie_id) AS total_seasons,
  calc_series_total_episodes(t.serie_id) AS total_episodes,
  calc_series_is_long_running(t.serie_id) AS is_long_running,
  calc_series_seasons(t.serie_id) AS seasons,
  calc_series_series_ratings(t.serie_id) AS series_ratings,
  calc_series_rating(t.serie_id) AS rating,
  calc_series_is_good(t.serie_id) AS is_good
FROM series t;

CREATE OR REPLACE VIEW vw_seasons WITH (security_invoker = ON) AS
