  t.series,
  calc_seasons_show_title(t.season_id) AS show_title,
  calc_seasons_show_description(t.season_id) AS show_description,
  calc_seasons_show_network(t.season_id) AS show_network,
  t.season_number,
  t.title,
  t.description,
  t.start_airdate,
  t.end_airdate,
  calc_seasons_episode_count(t.season_id) AS episode_count,
  calc_seasons_episodes(t.season_id) AS episodes,
  t.mock_data_notes
FROM seasons t;

